import { HttpClient } from './http-client';

/**
 * Custom error class for API-related errors.
 */
export class ApiError extends Error {
  public readonly statusCode: number;
  public readonly endpoint: string;

  public constructor(message: string, statusCode: number, endpoint: string) {
    super(message);
    this.name = 'ApiError';
    this.statusCode = statusCode;
    this.endpoint = endpoint;
  }
}

/**
 * Custom error class for user not found scenarios.
 */
export class UserNotFoundError extends ApiError {
  public constructor(userId: string) {
    super(`User not found: ${userId}`, 404, `/api/users/${userId}`);
    this.name = 'UserNotFoundError';
  }
}

/**
 * User data structure returned from the API.
 */
export interface User {
  id: string;
  name: string;
  email: string;
  createdAt: Date;
}

/**
 * Fetches user data from the API by user ID.
 * @param userId - The unique identifier of the user to fetch.
 * @param httpClient - The HTTP client instance to use for requests.
 * @returns The user data if found.
 * @throws {UserNotFoundError} If the user does not exist.
 * @throws {ApiError} If the API request fails for other reasons.
 */
export const fetchUserById = async (
  userId: string,
  httpClient: HttpClient
): Promise<User> => {
  const endpoint = `/api/users/${userId}`;

  const response = await httpClient.get(endpoint);

  if (response.status === 404) {
    throw new UserNotFoundError(userId);
  }

  if (!response.ok) {
    throw new ApiError(
      `Failed to fetch user: ${response.statusText}`,
      response.status,
      endpoint
    );
  }

  const userData: User = await response.json();

  return userData;
};
